class Solution:
    def nextLargerNodes(self, head):
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        n = len(vals)
        res = [0] * n
        for i in range(n):
            for j in range(i + 1, n):
                if vals[j] > vals[i]:
                    res[i] = vals[j]
                    break
        return res

