class Solution:
    def nextLargerNodes(self, head):
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        n = len(vals)
        res = [0] * n
        stack = []
        for i, v in enumerate(vals):
            while stack and vals[stack[-1]] < v:
                res[stack.pop()] = v
            stack.append(i)
        return res

