var nextLargerNodes = function(head) {
    const vals = [];
    let node = head;
    while (node) {
        vals.push(node.val);
        node = node.next;
    }
    const n = vals.length;
    const res = new Array(n).fill(0);
    const stack = [];
    for (let i = 0; i < n; i++) {
        while (stack.length && vals[stack[stack.length - 1]] < vals[i]) {
            res[stack.pop()] = vals[i];
        }
        stack.push(i);
    }
    return res;
};
